// lib/db.js
import { unstable_cache } from 'next/cache';

export async function getAllProducts() {
  // Simulate database delay
  await new Promise(resolve => setTimeout(resolve, 100));

  return [
    { id: 1, name: 'Laptop', price: 999 },
    { id: 2, name: 'Phone', price: 699 },
    { id: 3, name: 'Tablet', price: 499 },
    { id: 4, name: 'Headphones', price: 199 },
    { id: 5, name: 'Watch', price: 299 }
  ];
}

// Keep catalog reads fast while allowing every catalog view to share one invalidation tag.
export const getCachedProducts = unstable_cache(getAllProducts, ['products'], {
  tags: ['products'],
  revalidate: 300
});


