// app/page.tsx
import { revalidateTag } from 'next/cache';
import { getCachedProducts } from '@/lib/db';

export const metadata = {
  title: 'Product catalog | Admin'
};

export default async function Page() {
  const products = await getCachedProducts();

  async function syncCatalog() {
    'use server';

    // Mark the shared catalog cache stale. The next read refreshes it in the background.
    revalidateTag('products', 'max');
  }

  return (
    <main className="catalog-shell">
      <header className="catalog-header">
        <div>
          <p className="eyebrow">Commerce operations</p>
          <h1>Product catalog</h1>
          <p className="muted">Browse pricing, inventory, and availability across your assortment.</p>
        </div>
        <form action={syncCatalog}>
          <button className="sync-button" type="submit">
            <span aria-hidden="true">↻</span>
            Sync latest catalog
          </button>
        </form>
      </header>

      <section className="catalog-toolbar" aria-label="Catalog summary">
        <div>
          <span className="summary-label">All products</span>
          <strong>{products.length}</strong>
        </div>
        <p className="sync-note">Catalog data is refreshed in the background after a sync.</p>
      </section>

      <section className="table-frame" aria-labelledby="catalog-table-title">
        <h2 id="catalog-table-title" className="sr-only">All products</h2>
        <table>
          <thead>
            <tr>
              <th scope="col">Product</th>
              <th scope="col">SKU</th>
              <th scope="col">Price</th>
              <th scope="col">Status</th>
              <th scope="col" className="align-right">Inventory</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id}>
                <td className="product-name">{product.name}</td>
                <td className="sku">PRD-{String(product.id).padStart(4, '0')}</td>
                <td>${product.price.toFixed(2)}</td>
                <td><span className="status"><span aria-hidden="true" />Active</span></td>
                <td className="align-right">Available</td>
              </tr>
            ))}
          </tbody>
        </table>
      </section>
    </main>
  );
}


